#!/usr/bin/env node
/**
 * build-ds-bundle.mjs — regenerate ds-bundle/styles.css for Claude Design.
 *
 * Extracts the Varm minimalism token layer from the live source so the bundle
 * never drifts from the app:
 *   - :root / .dark CSS variables  ← src/index.css
 *   - fluid type scale (--text-*)  ← tailwind.config.ts  fontSize{}
 *   - editorial utilities + motion ← src/index.css  @layer utilities + keyframes
 *
 * Strips Tailwind-only syntax (@tailwind, @apply) and re-emits the @layer base
 * rules as plain CSS, because Claude Design renders styles.css without a
 * Tailwind build step.
 *
 * Run:  node scripts/build-ds-bundle.mjs   (or: bun run scripts/build-ds-bundle.mjs)
 */
import { readFileSync, writeFileSync, mkdirSync, existsSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const root = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const read = (p) => readFileSync(resolve(root, p), "utf8");

/** Extract a brace-balanced block body for the first `selector { ... }`. */
function block(css, selector) {
  const start = css.indexOf(selector);
  if (start === -1) throw new Error(`selector not found: ${selector}`);
  const open = css.indexOf("{", start);
  let depth = 0, i = open;
  for (; i < css.length; i++) {
    if (css[i] === "{") depth++;
    else if (css[i] === "}") { depth--; if (depth === 0) break; }
  }
  return css.slice(open + 1, i).replace(/^\n+|\s+$/g, "");
}

const indexCss = read("src/index.css");
const twConfig = read("tailwind.config.ts");
const indexHtml = read("index.html");

// 1. Font @import from the <link> in index.html
const fontHref = (indexHtml.match(/href="(https:\/\/fonts\.googleapis\.com\/css2[^"]+)"/) || [])[1];
if (!fontHref) throw new Error("Google Fonts <link> not found in index.html");

// 2. token vars
const rootVars = block(indexCss, ":root");
const darkVars = block(indexCss, ".dark");

// 3. type scale from tailwind fontSize{}
const fontSizeBlock = block(twConfig, "fontSize:");
const textVars = [...fontSizeBlock.matchAll(/(\w+):\s*\[\s*"([^"]+)"/g)]
  .map(([, name, value]) => `  --text-${name}: ${value};`)
  .join("\n");

// 4. utilities + motion (plain CSS already — no @apply inside)
const utilities = block(indexCss, "@layer utilities");
const motionStart = indexCss.indexOf("@keyframes fade-up");
const motion = motionStart === -1 ? "" : indexCss.slice(motionStart).trim();

// 5. assemble
const out = `@import url("${fontHref}");

/* ════════════════════════════════════════════════════════════════
   JOEL-DESIGN · Varm minimalism — token foundation for Claude Design
   AUTO-GENERATED by scripts/build-ds-bundle.mjs — do not edit by hand.
   Source of truth: src/index.css + tailwind.config.ts
   ════════════════════════════════════════════════════════════════ */

:root {
${rootVars}

  /* Fluid type scale (from tailwind.config.ts) */
${textVars}
}

.dark {
${darkVars}
}

/* ── Base (plain CSS — @apply rules from src/index.css re-emitted) ── */
body {
  background: hsl(var(--background));
  color: hsl(var(--foreground));
  font-family: var(--font-serif);
  font-size: 1.0625rem;
  line-height: 1.75;
  font-feature-settings: 'kern' 1, 'liga' 1, 'calt' 1;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-rendering: optimizeLegibility;
}
::selection { background: hsl(var(--accent)); color: hsl(var(--accent-foreground)); }
h1, h2, h3, h4, h5, h6 { font-family: var(--font-serif); font-weight: 500; text-wrap: balance; }
p { text-wrap: pretty; }
:focus-visible { outline: 2px solid hsl(var(--ring)); outline-offset: 2px; border-radius: 2px; }

/* ── Editorial utilities (from src/index.css @layer utilities) ── */
${utilities}

/* ── Motion ── */
${motion}
`;

mkdirSync(resolve(root, "ds-bundle"), { recursive: true });
writeFileSync(resolve(root, "ds-bundle/styles.css"), out);

// keep README = conventions header in sync
const conv = resolve(root, ".design-sync/conventions.md");
if (existsSync(conv)) writeFileSync(resolve(root, "ds-bundle/README.md"), read(".design-sync/conventions.md"));

const kb = (out.length / 1024).toFixed(1);
console.log(`ds-bundle/styles.css written (${kb} KB)`);
console.log(`  root vars: ${rootVars.split("\n").filter((l) => l.includes("--")).length}`);
console.log(`  text vars: ${textVars.split("\n").length}`);
console.log(`  utilities: ${(utilities.match(/^\s*\.[\w-]+\s*\{/gm) || []).length} class blocks`);
